SELECT C.SITE_CD AS siteCd , C.CTT_ID AS cttId , C.LANG_SE AS langSe , C.CTT_NM AS cttNm , C.CTT_DESC AS cttDesc , C.USE_YN AS useYn , C.PUB_YN AS pubYn , C.PUB_ST_YMD AS pubStYmd , C.PUB_ST_HHMM AS pubStHhmm , C.PUB_END_YMD AS pubEndYmd , C.PUB_END_HHMM AS pubEndHhmm , C.CTT_RMK AS cttRmk , S.SN AS seoSn , S.META_TTL AS metaTtl , S.META_DESC AS metaDesc , TO_CHAR(C.CRT_AT, 'YYYY-MM-DD HH24:MI:SS') AS crtAt , TO_CHAR(C.UPD_AT, 'YYYY-MM-DD HH24:MI:SS') AS updAt FROM CMS_CTT C LEFT JOIN CMS_CTT_SEO S ON S.SITE_CD = C.SITE_CD AND S.CTT_ID = C.CTT_ID AND S.LANG_SE = C.LANG_SE
C.SITE_CD = #{siteCd}
AND C.LANG_SE = #{langSe}
AND C.USE_YN = #{useYn}
AND C.PUB_YN = #{pubYn}
AND C.CTT_NM LIKE '%' || #{keyword} || '%'
ORDER BY C.CRT_AT DESC

