mapper.select:
SELECT SN        AS sn
     , SITE_CD   AS siteCd
     , CTT_ID    AS cttId
     , LANG_SE   AS langSe
     , META_TTL  AS metaTtl
     , META_DESC AS metaDesc
  FROM CMS_CTT_SEO
 WHERE SITE_CD = #{siteCd}
   AND CTT_ID  = #{cttId}
   AND LANG_SE = #{langSe}

mapper.insert:
INSERT INTO CMS_CTT_SEO (
    SN
  , SITE_CD
  , CTT_ID
  , LANG_SE
  , META_TTL
  , META_DESC
  , 
) VALUES (
    (SELECT NVL(MAX(SN), 0) + 1 FROM CMS_CTT_SEO
      WHERE SITE_CD = #{siteCd}
        AND CTT_ID  = #{cttId}
        AND LANG_SE = #{langSe})
  , #{siteCd}
  , #{cttId}
  , #{langSe}
  , #{metaTtl}
  , #{metaDesc}
  , 
)

mapper.update:
UPDATE CMS_CTT_SEO
   SET META_TTL  = #{vo.metaTtl}
     , META_DESC = #{vo.metaDesc}
     , 
 WHERE SITE_CD = #{siteCd}
   AND CTT_ID  = #{cttId}
   AND LANG_SE = #{langSe}

mapper.delete:
